  performAutoFill: () => void;
  performDispatch: () => void; 
  selectDispatchSlot: (techId: string, techName: string, time: string) => void; // New Action
  finalizeDispatch: () => void; // Updated Action (no args, uses state)

  performDiagnosis: (ticketId?: string) => Promise<void>;
