export const CurioService = {
  async generateRealDiagnosis(ticketId: string, ticket: Ticket): Promise<Partial<Diagnosis>> {
    const reasoningChain: ReasoningStep[] = [];
    const pushStep = (system: ReasoningStep['system'], action: string, status: ReasoningStep['status'], input?: any, output?: any) => {
        reasoningChain.push({
            id: Math.random().toString(),
            system, action, status,
            result: status === 'complete' ? 'Success' : undefined,
            input, output,
            timestamp: Date.now(),
            duration: Math.floor(Math.random() * 500) + 100
        });
    };

    pushStep('Reasoning', 'Initializing Curio Agent (Technical Report v1.2)...', 'working');

    // 🔴 THE GOLDEN PATH (Müller Logistik / ETM 214 / 91165099)
    const isDemoCase = ticket.equipment.serialNumber?.includes('91165099') || 
                       ticket.customer.name.includes('Müller') ||
                       ticket.error.customerReport.toLowerCase().includes('aus');

    if (isDemoCase) {
        await new Promise(r => setTimeout(r, 800));
        pushStep('History', 'Checking Service History for SN 91165099', 'complete', { serial: '91165099' }, { result: 'Extremely high history: 39 service entries detected.' });

        await new Promise(r => setTimeout(r, 600));
        pushStep('Manuals', 'Correlating 3xxx Errors with Voltage Drop', 'complete', { codes: '3xxx' }, { result: 'Mechanical resistance in steering motor leads to peak current and voltage collapse.' });

        await new Promise(r => setTimeout(r, 600));
        pushStep('IoT', 'Monitoring CAN-Bus Activity Node 4', 'complete', { serial: '91165099' }, { result: 'High CAN-Bus activity on Node 4. Inconsistent Ist-Values.' });

        await new Promise(r => setTimeout(r, 600));
        pushStep('Reasoning', 'Determining Root Cause (Discriminator Logic)', 'complete', {}, { result: 'No Sensor Error 3154. Voltage drops confirmed. Root Cause: Slewing Ring (Drehkranzlager).' });

        return {
            ticketId,
            timestamp: Date.now(),
            primaryFault: {
                fault: 'Drehkranzlager verschlissen / Schwergängig',
                confidence: 48,
                reasoning: 'Die Fehler deuten stark auf die Folgen von hohem mechanischem Widerstand hin (Spannungseinbrüche). Die extrem hohe Anzahl früherer Service-Einsätze (39) spricht ebenfalls für ein schwer fassbares, mechanisches Problem am Drehkranz.',
                shortReasoning: 'Mechanischer Widerstand -> Spannungseinbruch.'
            },
            secondaryFaults: [
                { fault: 'Sensorlager; kpl. montiert', confidence: 13, reasoning: 'Mögliche falsche Ist-Werte bei hohen Vibrationen.' },
                { fault: 'Initiator (Sonder NPN)', confidence: 11, reasoning: 'Fehlerhafte Höhenerkennung führt zu Schleichgang.' }
            ],
            requiredParts: RECOMMENDED_PARTS.filter(p => p.id === '50452065' || p.id === '51509314' || p.id === '51470075'),
            reasoningChain: reasoningChain,
            isComplete: true
        };
    }

    // Generic fallback for other cases...
    return this.getSimulationResult(ticketId, ticket);
  },

  getSimulationResult(ticketId: string, ticket: Ticket): Partial<Diagnosis> {
    return {
      ticketId,
      timestamp: Date.now(),
      primaryFault: {
        fault: 'Hydraulic Pump Motor Failure (Cluster 3)',
        confidence: 89,
        reasoning: 'Symptoms match Cluster 3 (Hydraulics). Lack of external oil leak suggests internal component failure.',
        shortReasoning: 'Cluster 3 match. No external leak.'
      },
      secondaryFaults: [],
      requiredParts: RECOMMENDED_PARTS.slice(3, 5),
      reasoningChain: [
          { id: '1', system: 'Manuals', action: 'Analyze Symptom', status: 'complete', result: 'Hydraulic Fault', timestamp: Date.now() },
          { id: '2', system: 'IoT', action: 'Read Sensor Data', status: 'complete', result: 'Pressure Low', timestamp: Date.now() }
      ],
      isComplete: true
    };
  }
};

