    set(state => ({
      sapForm: {
        ...state.sapForm,
        equipment: email.data!.equipment,
        soldToParty: email.data!.debitorId,
        priority: email.data!.priority,
        shortText: email.data!.desc,
        isDirty: true
      }
    }));
  },
  performDiagnosis: () => {
    const { addAgentLog } = get();
    set(state => ({ agent: { ...state.agent, status: 'diagnosing' } }));
    addAgentLog('thinking', 'Running multi-agent diagnosis...');
    setTimeout(() => {
      set(state => ({
        diagnosis: {
          ticketId: '11447115',
          timestamp: Date.now(),
          primaryFault: { fault: 'Hydraulic Pump Failure', confidence: 92, reasoning: 'Sensor data indicates pressure drop.' },
          secondaryFaults: [],
