    get().addAgentLog('action', 'Opening IFS FSM for scheduling...');
    get().openApp('fsm');
  },
  selectDispatchSlot: (techId, techName, time) => set({
    selectedSlot: { techId, techName, time },
    dispatchStatus: 'review'
  }),
  finalizeDispatch: () => {
    const { selectedSlot, addAgentLog } = get();
