export const TicketInspector = (props: any) => {
    const { diagnosis, closeTicketAnalysis, submitDiagnosisFeedback, performDispatch } = useOS();

    if (!diagnosis) return (
        <div className="h-full flex items-center justify-center text-slate-500 flex-col gap-4">
            <Loader2 className="w-8 h-8 animate-spin text-indigo-500" />
            <span>Loading Ticket Intelligence...</span>
        </div>
    );

    const steps = diagnosis.reasoningChain || [];
    const isFeedbackGiven = !!diagnosis.feedback;

    const faultText = (diagnosis.primaryFault?.fault || "").toLowerCase();
    const isSlewingRing = faultText.includes('drehkranz') || faultText.includes('50452065');

    let evidenceCards = [];

    if (isSlewingRing) {
        // GOLD STANDARD PDF EVIDENCE
        evidenceCards = [
            { 
                title: "Service History", 
                source: "Fleet Analytics", 
                value: "39 Previous Incidents", 
                status: "Anomalous", 
                statusColor: "red",
                icon: History 
            },
            { 
                title: "Voltage Monitoring", 
                source: "IoT Stream", 
                value: "Severe Drops Detected", 
                status: "Critical", 
                statusColor: "red",
                icon: Zap 
            },
            { 
                title: "Acoustic Analysis", 
                source: "Porta Voice Log", 
                value: "Knocking / Grinding", 
                status: "Suspected", 
                statusColor: "amber",
                icon: Mic 
            },
            { 
                title: "Discriminator Gate", 
                source: "Rule Engine", 
                value: "No Sensor-Error 3154", 
                status: "Verified", 
                statusColor: "emerald",
                icon: Shield 
            }
        ];
    } else {
        // DEFAULT EVIDENCE
        evidenceCards = [
            { title: "Telemetry Signature", source: "IoT Stream", value: "Pressure Drop", status: "Critical", statusColor: "red", icon: Activity },
            { title: "Error Code Match", source: "Manuals KB", value: "E0015: Hydr. Pump", status: "Verified", statusColor: "indigo", icon: Database },
            { title: "Historical Correlation", source: "Fleet History", value: "91% Match", status: "High", statusColor: "emerald", icon: Clock },
            { title: "Parts Availability", source: "Inventory", value: "Ready in Van", status: "Ready", statusColor: "emerald", icon: Box }
        ];
    }

    return (
        <div className="h-full flex flex-col bg-[#05050A] font-sans selection:bg-indigo-500/20">
            {/* Top Bar */}
            <div className="h-16 border-b border-white/5 flex items-center px-6 shrink-0 bg-[#0A0A0F] justify-between">
                <div className="flex items-center gap-4">
                    <button onClick={closeTicketAnalysis} className="p-2 hover:bg-white/5 rounded-lg text-slate-400 hover:text-white transition-colors">
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <h1 className="text-white font-bold text-sm flex items-center gap-2">
                            Case Analysis <span className="text-slate-500 font-normal">#{diagnosis.ticketId.replace('T-','')}</span>
                        </h1>
                        <div className="text-[10px] text-slate-500 flex items-center gap-2">
                            <span>Started {new Date(diagnosis.timestamp).toLocaleTimeString()}</span>
                            <span className="w-1 h-1 rounded-full bg-slate-700"></span>
                            <span className="text-indigo-400">Curio Agent v2.5</span>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    {isFeedbackGiven ? (
                        <div className={`px-4 py-2 rounded-lg text-xs font-bold border flex items-center gap-2 ${diagnosis.feedback?.status === 'approved' ? 'bg-emerald-500/5 border-emerald-500/20 text-emerald-400' : 'bg-red-500/5 border-red-500/20 text-red-400'}`}>
                            {diagnosis.feedback?.status === 'approved' ? <CheckCircle className="w-4 h-4" /> : <X className="w-4 h-4" />}
                            {diagnosis.feedback?.status === 'approved' ? 'Decision: Approved' : 'Decision: Rejected'}
                        </div>
                    ) : (
                        <>
                            <button onClick={() => submitDiagnosisFeedback(diagnosis.ticketId, 'rejected', 'Incorrect diagnosis')} className="px-4 py-2 rounded-lg text-xs font-bold text-slate-400 hover:text-white hover:bg-white/5 transition-colors">Reject Analysis</button>
                            <button onClick={() => { submitDiagnosisFeedback(diagnosis.ticketId, 'approved'); performDispatch(); }} className="bg-white text-black px-5 py-2 rounded-lg text-xs font-bold flex items-center gap-2 hover:bg-gray-200 transition-colors shadow-[0_0_20px_rgba(255,255,255,0.1)]">
                                <Zap className="w-3.5 h-3.5 fill-black" /> Approve & Dispatch
                            </button>
                        </>
                    )}
                </div>
            </div>

            <div className="flex-1 flex overflow-hidden">
                {/* LEFT: TIMELINE */}
                <div className="w-[400px] border-r border-white/5 bg-[#08080C] flex flex-col">
                    <div className="p-5 border-b border-white/5"><h2 className="text-xs font-bold text-white uppercase tracking-widest flex items-center gap-2"><Activity className="w-3.5 h-3.5 text-indigo-500" /> Investigation Steps</h2></div>
                    <div className="flex-1 overflow-y-auto p-5 relative">
                        <div className="absolute left-[33px] top-5 bottom-5 w-px bg-white/5"></div>
                        <div className="space-y-6">{steps.map((step, idx) => (<TimelineStep key={step.id} step={step} index={idx} isLast={idx === steps.length - 1} />))}</div>
                    </div>
                </div>

                {/* RIGHT: DOSSIER */}
                <div className="flex-1 overflow-y-auto bg-[#05050A] p-8 xl:p-12">
                    <div className="max-w-4xl mx-auto space-y-8">
                        <div className="flex items-start justify-between">
                            <div>
                                <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Primary Diagnosis</div>
                                <h1 className="text-3xl font-bold text-white mb-2">{diagnosis.primaryFault.fault}</h1>
                                <p className="text-slate-400 text-sm max-w-2xl leading-relaxed">{diagnosis.primaryFault.reasoning}</p>
                            </div>
                            <div className="text-right">
                                <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Confidence Score</div>
                                <div className="text-5xl font-bold text-white tracking-tighter">{Math.round(diagnosis.primaryFault.confidence)}<span className="text-2xl text-slate-600 font-normal">%</span></div>
                            </div>
                        </div>

                        <div className="h-px bg-white/5 w-full"></div>

                        <div>
                            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2"><FileText className="w-4 h-4" /> Key Evidence Collected</h3>
                            <div className="grid grid-cols-2 gap-4">{evidenceCards.map((card, i) => (<EvidenceCard key={i} title={card.title} source={card.source} value={card.value} status={card.status} statusColor={card.statusColor} icon={card.icon} />))}</div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const TimelineStep = ({ step, index, isLast }: any) => (
    <div className="relative pl-12 group">
        <div className={`absolute left-[29px] top-1 w-2.5 h-2.5 rounded-full border-2 border-[#08080C] z-10 transition-colors ${step.status === 'complete' ? 'bg-indigo-500 group-hover:bg-white' : 'bg-amber-500'}`}></div>
        <div className="flex flex-col gap-1 pb-4">
            <div className="flex items-center justify-between"><span className="text-xs font-bold text-slate-300 group-hover:text-white transition-colors">{step.action}</span><span className="text-[9px] font-mono text-slate-600">{step.duration}ms</span></div>
            <div className="flex items-center gap-2"><span className={`text-[9px] px-1.5 py-0.5 rounded border ${getSystemBadgeStyle(step.system)}`}>{step.system}</span>{step.result && <span className="text-[10px] text-slate-500 truncate max-w-[150px]">{step.result}</span>}</div>
        </div>
    </div>
);

const EvidenceCard = ({ title, source, value, status, statusColor = 'indigo', icon: Icon }: any) => {
    const statusStyles: any = { emerald: "bg-emerald-500/10 text-emerald-400 border-emerald-500/20", red: "bg-red-500/10 text-red-400 border-red-500/20", amber: "bg-amber-500/10 text-amber-400 border-amber-500/20", indigo: "bg-indigo-500/10 text-indigo-400 border-indigo-500/20" };
    return (
        <div className="bg-[#0A0A0F] border border-white/5 rounded-xl p-5 hover:border-white/10 transition-colors group">
            <div className="flex justify-between items-start mb-3"><div className="p-2 rounded-lg bg-white/5 group-hover:bg-white/10 transition-colors text-slate-400 group-hover:text-white"><Icon className="w-4 h-4" /></div><span className={`text-[10px] font-bold px-2 py-1 rounded border ${statusStyles[statusColor]}`}>{status}</span></div>
            <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">{source}</div>
            <div className="text-lg font-bold text-white mb-1">{value}</div>
            <div className="text-[10px] text-slate-500">{title}</div>
        </div>
    );
};

const getSystemBadgeStyle = (system: string) => {
    switch(system) {
        case 'SAP': return 'bg-blue-900/20 text-blue-400 border-blue-500/20';
        case 'IoT': return 'bg-purple-900/20 text-purple-400 border-purple-500/20';
        case 'Manuals': return 'bg-slate-800 text-slate-400 border-slate-600/30';
        case 'History': return 'bg-rose-900/20 text-rose-400 border-rose-500/20';
        case 'Inventory': return 'bg-amber-900/20 text-amber-400 border-amber-500/20';
        default: return 'bg-white/5 text-slate-400 border-white/10';
    }
};

