import React, { useEffect, useState, useRef } from 'react';
import { useOS } from '../../store';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Search, Filter, ChevronDown, ChevronRight, 
  Settings, Calendar, Users, Map, Activity,
  Maximize2, RefreshCw, LogOut, Box, CheckCircle, MousePointer2
} from 'lucide-react';

export const FSM: React.FC = () => {
  const { assignedTech, agent, diagnosis, switchToApp, toggleSmartLens, tickets, dispatchStatus, selectDispatchSlot } = useOS();
  const [showNewJob, setShowNewJob] = useState(false);

  // Interaction State
  const [hoveredCell, setHoveredCell] = useState<{ resourceId: string, time: number } | null>(null);

  // Use the top/active ticket for the dynamic job label
  // Fixed: Added 'number' to the fallback object to ensure TS knows it exists on both union types.
  const activeTicket = tickets[0] || { number: '00000000', customer: { name: 'Unknown Co.' } };

  // Trigger animation when tech is assigned (Legacy effect kept for fallback)
  useEffect(() => {
    if (assignedTech && dispatchStatus === 'confirmed') {
      const timer = setTimeout(() => setShowNewJob(true), 500);
      return () => clearTimeout(timer);
    }
  }, [assignedTech, dispatchStatus]);

  const handleMobileSwitch = () => {
      switchToApp('mobile');
      // Automatically open the Smart Lens when switching to mobile for demo purposes
      setTimeout(() => toggleSmartLens(true), 800);
  };

  const handleGridMouseMove = (e: React.MouseEvent, resourceId: string) => {
      if (dispatchStatus !== 'planning') return;

      const rect = e.currentTarget.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const width = rect.width;

      // Calculate time (8:00 to 18:00 = 10 hours)
      // Percentage across width
      const pct = Math.max(0, Math.min(1, x / width));
      const hours = 10 * pct; 
      // Snap to 15 min (0.25h)
      const snappedHours = Math.round(hours * 4) / 4;

      setHoveredCell({ resourceId, time: 8 + snappedHours });
  };

  const handleGridMouseLeave = () => {
      setHoveredCell(null);
  };

  const handleGridClick = (resourceId: string) => {
      if (dispatchStatus !== 'planning' || !hoveredCell) return;

      const resource = RESOURCES.find(r => r.id === resourceId);
      if (resource) {
          const timeStr = `${Math.floor(hoveredCell.time)}:${(Math.round((hoveredCell.time % 1) * 60)).toString().padStart(2, '0')}`;
          selectDispatchSlot(resource.id, resource.name, timeStr);
      }
  };

  // Helper to format time for the ghost cursor
  const formatTime = (time: number) => {
      const h = Math.floor(time);
      const m = Math.round((time - h) * 60);
      return `${h}:${m.toString().padStart(2, '0')}`;
  };

  return (
    <div className="h-full flex flex-col bg-[#E0E0E0] font-sans text-[10px] xl:text-xs text-[#333] overflow-hidden select-none border border-gray-400 transition-all">

       {/* 1. IFS PURPLE HEADER */}
       <div className="h-8 xl:h-10 bg-[#5B2C6F] flex items-center px-2 xl:px-4 justify-between shrink-0 text-white relative z-50">
          <div className="flex items-end h-full gap-1 pt-1 overflow-x-auto no-scrollbar">
             <Tab label="Resources" active />
             <Tab label="Activities" />
             <Tab label="Mapping" />
             <Tab label="Advanced Mapping" />
             <Tab label="Compare" />
             <Tab label="System Status" />
             <Tab label="Analysis" />
          </div>
          <div className="flex items-center gap-2 pl-4 bg-[#5B2C6F]">
             <div className="flex bg-[#4A235A] rounded px-2 py-0.5 items-center gap-1 border border-white/20">
                <Search className="w-3 h-3 text-white/70" />
                <span className="text-white/50 italic text-[10px] xl:text-xs">Find...</span>
             </div>
             <button className="flex items-center gap-1 bg-[#4A235A] px-2 py-0.5 rounded border border-white/20 hover:bg-[#6C3483] text-[10px] xl:text-xs">
                <RefreshCw className="w-3 h-3" /> Refresh
             </button>
             <button className="bg-[#4A235A] px-2 py-0.5 rounded border border-white/20 hover:bg-[#6C3483] text-[10px] xl:text-xs">Logoff</button>
          </div>
       </div>

       {/* PLANNING MODE BANNER */}
       <AnimatePresence>
       {dispatchStatus === 'planning' && (
           <motion.div 
             initial={{ height: 0, opacity: 0 }}
             animate={{ height: 'auto', opacity: 1 }}
             exit={{ height: 0, opacity: 0 }}
             className="bg-amber-100 border-b border-amber-300 text-amber-900 px-4 py-2 flex items-center justify-between shadow-inner relative z-40 overflow-hidden"
           >
              <div className="flex items-center gap-2">
                 <MousePointer2 className="w-4 h-4 animate-bounce" />
                 <span className="font-bold text-sm">Select a time slot to dispatch Job #{activeTicket.number}</span>
                 <span className="text-xs opacity-70">(Click on any technician timeline)</span>
              </div>
              <div className="text-xs font-mono bg-white/50 px-2 py-0.5 rounded border border-amber-200">
                  Planning Mode Active
              </div>
           </motion.div>
       )}
       </AnimatePresence>

       {/* 2. TOOLBAR */}
