                   <div className="pl-4 py-1 text-gray-500 text-[10px] xl:text-xs">Normal (54)</div>
                   <div className="pl-4 py-1 text-gray-500 text-[10px] xl:text-xs">Reactive (1)</div>
                </AccordionItem>

                <AccordionItem title="Unplanned Activities" count={5} color="bg-green-100 border-green-300" textColor="text-green-800" />

                <AccordionItem title="Unplanned Activity in jeopardy" count={5} color="bg-orange-100 border-orange-300" textColor="text-orange-800" />

                <div className="mt-4 border border-[#CCCCCC] bg-white">
                   <div className="bg-[#EFEFEF] border-b border-[#CCCCCC] px-2 py-1 font-bold text-[10px] xl:text-xs">Backlog</div>
                   {[...Array(8)].map((_,i) => (
                      <div key={i} className="flex justify-between px-2 py-1 border-b border-[#F0F0F0] text-gray-600 hover:bg-blue-50 text-[10px] xl:text-xs cursor-pointer">
