      const newEmail: Email = {
        id: `e-${Date.now()}`,
        sender: 'AEDIL Porta <intake@aedil.ai>',
        subject: data.emailSubject,
        time: 'Gerade eben',
        unread: true,
        body: data.emailBody,
        data: { 
            ticketId: newTicket.number, 
            customer: data.customer, 
            customerAddress: generatedAddress, 
            debitorId: generatedDebitorId, 
            equipment: data.equipment, 
            error: data.error, 
            priority: data.priority, 
            desc: data.desc 
        }
      };

      set(state => ({
        tickets: [newTicket, ...state.tickets],
        emails: [newEmail, ...state.emails],
        sapForm: {
          ...state.sapForm,
          customerAddress: generatedAddress, 
          soldToParty: generatedDebitorId,
          customerName: data.customer,
          equipment: data.equipment,
          priority: data.priority,
          shortText: data.desc,
          errorDesc: data.emailBody,
          isDirty: true
        },
        porta: { ...state.porta, status: 'completed' }
      }));

      addAgentLog('success', 'Ticket und E-Mail erfolgreich generiert.');

      setTimeout(() => {
        closeApp('porta');
        openApp('outlook');
        selectEmail(newEmail.id);
        set(state => ({ porta: { messages: [{ id: Date.now().toString(), sender: 'ai', text: 'Jungheinrich Service Support. Nennen Sie bitte Ihren Namen und Ihre Firma.', timestamp: Date.now() }], status: 'idle', transcript: '' } }));
      }, 1000);
    } catch (err) {
      set(state => ({ porta: { ...state.porta, status: 'idle' } }));
    }
  },
  updateSapField: (field, value) => set(state => ({
    sapForm: { ...state.sapForm, [field]: value, isDirty: true }
  })),
  updateNodeProvider: (nodeId, provider) => set(state => ({
    workflowNodes: state.workflowNodes.map(n => n.id === nodeId ? { ...n, provider } : n)
  })),
  addWorkflowNode: (type, label, provider, parentId, pos) => set(state => {
    const newNode: WorkflowNode = { id: Math.random().toString(), type, label, position: pos || { x: 100, y: 100 }, provider, status: 'active' };
    const newEdge: WorkflowEdge | null = parentId ? { id: Math.random().toString(), source: parentId, target: newNode.id } : null;
    return {
      workflowNodes: [...state.workflowNodes, newNode],
      workflowEdges: newEdge ? [...state.workflowEdges, newEdge] : state.workflowEdges
    };
  }),
  updateWorkflowNodePosition: (id, x, y) => set(state => ({
    workflowNodes: state.workflowNodes.map(n => n.id === id ? { ...n, position: { x, y } } : n)
  })),
  deleteWorkflowNode: (id) => set(state => ({
    workflowNodes: state.workflowNodes.filter(n => n.id !== id),
    workflowEdges: state.workflowEdges.filter(e => e.source !== id && e.target !== id)
  }))
}));

