        await new Promise(r => setTimeout(r, 800));
        pushStep('IoT', 'Monitoring CAN-Bus Activity Node 4', 'complete', { serial: '91165099' }, { result: 'High CAN-Bus activity on Node 4. Inconsistent Ist-Values.' });

        await new Promise(r => setTimeout(r, 600));
        pushStep('Reasoning', 'Determining Root Cause (Discriminator Logic)', 'complete', {}, { result: 'Verified: No Sensor-Error 3154. Voltage drops confirmed. Root Cause: Drehkranzlager.' });

        return {
            ticketId,
            timestamp: Date.now(),
            primaryFault: {
                fault: 'Rang 1: Rep. Satz; Drehkranzlager',
                confidence: 48.33,
                reasoning: 'Die Fehler deuten stark auf mechanischen Widerstand hin (Spannungsprobleme, generelle Lenkfehler). Fehlende Sensorfehler (z.B. 3154) schließen Sensorlager als Primärursache aus. 39 Vorreparaturen stützen mechanischen Verschleiß.',
