            { title: "Discriminator Gate", source: "Rule Engine", value: "No Sensor-Error 3154", status: "Verified", statusColor: "emerald", icon: Shield }
        ];
    } else {
        // DEFAULT EVIDENCE
        evidenceCards = [
            { title: "Telemetry Signature", source: "IoT Stream", value: "Pressure Drop", status: "Critical", statusColor: "red", icon: Activity },
