            <div className="flex items-center justify-between"><span className="text-xs font-bold text-slate-300 group-hover:text-white transition-colors">{step.action}</span><span className="text-[9px] font-mono text-slate-600">{step.duration}ms</span></div>
            <div className="flex items-center gap-2"><span className={`text-[9px] px-1.5 py-0.5 rounded border ${getSystemBadgeStyle(step.system)}`}>{step.system}</span>{step.result && <span className="text-[10px] text-slate-500 truncate max-w-[150px]">{step.result}</span>}</div>
        </div>
