// --- MAIN COMPONENT ---

export const WorkflowBuilder = (props: any) => {
  const { addToast } = props;

  // Use specific selectors
  const workflowNodes = useOS(state => state.workflowNodes);
  const workflowEdges = useOS(state => state.workflowEdges);
  const updateNodeProvider = useOS(state => state.updateNodeProvider);
  const addWorkflowNode = useOS(state => state.addWorkflowNode);
  const updateWorkflowNodePosition = useOS(state => state.updateWorkflowNodePosition);
  const deleteWorkflowNode = useOS(state => state.deleteWorkflowNode);

  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);

  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [zoom, setZoom] = useState(1);
  const [isDraggingCanvas, setIsDraggingCanvas] = useState(false);
  const [draggedNodeId, setDraggedNodeId] = useState<string | null>(null);
  const [isTestRunning, setIsTestRunning] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);
  const lastMousePos = useRef({ x: 0, y: 0 });
  const hasMoved = useRef(false);

  const selectedNode = workflowNodes.find(n => n.id === selectedNodeId);

  // --- ACTIONS ---

  const handleDeleteNode = () => {
      if (selectedNodeId) {
          deleteWorkflowNode(selectedNodeId);
          setSelectedNodeId(null);
      }
  };

  const handleDrop = (e: React.DragEvent) => {
      e.preventDefault();
      const providerKey = e.dataTransfer.getData('provider');
      if (!providerKey || !containerRef.current) return;

      const providerConfig = PROVIDER_LIBRARY[providerKey];
      if (!providerConfig) return;

      const rect = containerRef.current.getBoundingClientRect();
      const x = (e.clientX - rect.left - pan.x) / zoom;
      const y = (e.clientY - rect.top - pan.y) / zoom;

      let parentId = undefined;
      if (selectedNodeId) {
          const parent = workflowNodes.find(n => n.id === selectedNodeId);
          if (parent && isNextPhase(parent.type, providerConfig.type)) {
              parentId = selectedNodeId;
          }
      }

      if (!parentId && workflowNodes.length > 0) {
          const lastNode = workflowNodes[workflowNodes.length - 1];
          if (isNextPhase(lastNode.type, providerConfig.type)) {
              parentId = lastNode.id;
          }
      }

      let finalX = x;
      let finalY = y;

      finalX -= 120;
      finalY -= 60;

      addWorkflowNode(
          providerConfig.type, 
          providerConfig.type.charAt(0).toUpperCase() + providerConfig.type.slice(1), 
          providerKey, 
          parentId,
          { x: finalX, y: finalY }
      );

      addToast(`Added ${providerKey}`, 'success');
  };

  const isNextPhase = (current: NodeType, next: NodeType) => {
      const order = ['trigger', 'system', 'agent', 'logic', 'action'];
      const cIdx = order.indexOf(current);
      const nIdx = order.indexOf(next);
      return nIdx > cIdx; 
  };

  // --- EVENT HANDLERS ---

  const handleMouseDown = (e: React.MouseEvent) => {
    hasMoved.current = false;
    const target = e.target as HTMLElement;
    const nodeElement = target.closest('[data-node-id]');

    if (nodeElement) {
        const nodeId = nodeElement.getAttribute('data-node-id');
        if (nodeId) {
            setDraggedNodeId(nodeId);
            setSelectedNodeId(nodeId);
            lastMousePos.current = { x: e.clientX, y: e.clientY };
            e.stopPropagation();
            return;
        }
    }
    setIsDraggingCanvas(true);
    lastMousePos.current = { x: e.clientX, y: e.clientY };
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (draggedNodeId || isDraggingCanvas) hasMoved.current = true;
    const dx = e.clientX - lastMousePos.current.x;
    const dy = e.clientY - lastMousePos.current.y;
    lastMousePos.current = { x: e.clientX, y: e.clientY };

    if (draggedNodeId) {
        const node = workflowNodes.find(n => n.id === draggedNodeId);
        if (node) updateWorkflowNodePosition(draggedNodeId, node.position.x + (dx / zoom), node.position.y + (dy / zoom));
    } else if (isDraggingCanvas) {
        setPan(p => ({ x: p.x + dx, y: p.y + dy }));
    }
  };

  const handleMouseUp = () => { setIsDraggingCanvas(false); setDraggedNodeId(null); };

  const handleClick = (e: React.MouseEvent) => {
    if (hasMoved.current) return;
    if (!(e.target as HTMLElement).closest('[data-node-id]')) setSelectedNodeId(null);
  };

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        setZoom(z => Math.min(Math.max(0.5, z + (-e.deltaY * 0.001)), 2));
    } else {
        setPan(p => ({ x: p.x - e.deltaX, y: p.y - e.deltaY }));
    }
  };

  const handleRunTest = () => { 
      setIsTestRunning(true); 
      addToast('Validating workflow logic...', 'info');
      setTimeout(() => {
          setIsTestRunning(false);
          addToast('Workflow validation successful', 'success');
      }, 3000); 
  };

  return (
    <div className="h-full w-full flex bg-[#05050A] text-slate-300 overflow-hidden select-none font-sans">

      {/* LEFT SIDEBAR: PALETTE */}
      <div className="w-64 bg-[#0F1019] border-r border-white/10 flex flex-col z-20 shrink-0">
          <div className="p-4 border-b border-white/5">
              <h2 className="text-xs font-bold text-white uppercase tracking-widest flex items-center gap-2">
                  <Box className="w-3 h-3 text-indigo-500" /> Component Library
              </h2>
          </div>
          <div className="flex-1 overflow-y-auto p-2 space-y-6">
              {/* Render categories */}
              <PaletteCategory title="Intake Sources" type="trigger" />
              <PaletteCategory title="Systems of Record" type="system" />
              <PaletteCategory title="AEDIL Intelligence" type="agent" />
              <PaletteCategory title="Planning & Sched" type="logic" />
              <PaletteCategory title="Output & Actions" type="action" />
          </div>
          <div className="p-3 border-t border-white/5 bg-black/20 text-[10px] text-slate-500 text-center">
              Drag nodes to canvas
          </div>
      </div>

      {/* CANVAS AREA */}
      <div 
        ref={containerRef}
        className={`flex-1 relative w-full h-full overflow-hidden ${isDraggingCanvas ? 'cursor-grabbing' : 'cursor-default'}`}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onWheel={handleWheel}
        onClick={handleClick}
        onDragOver={(e) => e.preventDefault()}
        onDrop={handleDrop}
      >
        <div 
            style={{ 
                transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
                transformOrigin: '0 0',
                width: '100%',
                height: '100%'
            }}
            className="relative transition-transform duration-75 ease-out w-full h-full"
        >
            {/* Background Grid */}
            <div className="absolute -inset-[5000px] opacity-[0.1] pointer-events-none" 
                style={{ 
                    backgroundImage: `
                        linear-gradient(to right, #4F46E5 1px, transparent 1px),
                        linear-gradient(to bottom, #4F46E5 1px, transparent 1px)
                    `,
                    backgroundSize: '40px 40px'
                }} 
            />

            {/* Connections (Edges) */}
            <svg className="absolute -inset-[5000px] w-[10000px] h-[10000px] pointer-events-none overflow-visible z-0">
                <defs>
                    <linearGradient id="flow-grad" x1="0%" y1="0%" x2="100%" y2="0%"><stop offset="0%" stopColor="#6366F1" /><stop offset="100%" stopColor="#EC4899" /></linearGradient>
                    <filter id="glow-line"><feGaussianBlur stdDeviation="3" result="coloredBlur"/><feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
                    <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orient="auto">
                        <polygon points="0 0, 10 3.5, 0 7" fill="#334155" />
                    </marker>
                </defs>
                {workflowEdges.map(edge => {
                    const source = workflowNodes.find(n => n.id === edge.source);
                    const target = workflowNodes.find(n => n.id === edge.target);
                    if (!source || !target) return null;
                    const startX = source.position.x + 240; const startY = source.position.y + 60;
                    const endX = target.position.x; const endY = target.position.y + 60;

                    const deltaX = Math.abs(endX - startX);
                    const controlPointOffset = Math.max(deltaX * 0.5, 50);
                    const pathD = `M ${startX} ${startY} C ${startX + controlPointOffset} ${startY}, ${endX - controlPointOffset} ${endY}, ${endX} ${endY}`;

                    return (
                    <g key={edge.id}>
                        <path d={pathD} fill="none" stroke="#000" strokeWidth="6" strokeLinecap="round" opacity="0.5" />
                        <path d={pathD} fill="none" stroke="#334155" strokeWidth="3" strokeLinecap="round" markerEnd="url(#arrowhead)" />

                        {isTestRunning && (
                            <path d={pathD} fill="none" stroke="url(#flow-grad)" strokeWidth="3" strokeLinecap="round" className="animate-flow" filter="url(#glow-line)">
                                <animate attributeName="stroke-dasharray" values="0,1000; 1000,0" dur="1.5s" repeatCount="indefinite" />
                            </path>
                        )}
                        <circle r="3" fill="#F59E0B" filter="url(#glow-line)">
                            <animateMotion dur="2s" repeatCount="indefinite" path={pathD} />
                        </circle>
                    </g>
                    );
                })}
            </svg>

            {/* Nodes */}
            <div className="absolute top-0 left-0 w-full h-full z-10">
                <AnimatePresence>
                {workflowNodes.map(node => (
                    <GlassNode key={node.id} node={node} selected={selectedNodeId === node.id} isTesting={isTestRunning} />
                ))}
                </AnimatePresence>
            </div>
        </div>

        {/* View Controls */}
        <div className="absolute bottom-10 left-10 flex gap-2 z-50">
             <div className="bg-black/60 backdrop-blur border border-white/10 rounded-lg p-1 flex flex-col shadow-xl">
                 <button onClick={() => setZoom(z => Math.min(z + 0.2, 2))} className="p-2 hover:bg-white/10 rounded text-white"><ZoomIn className="w-4 h-4" /></button>
                 <button onClick={() => setZoom(z => Math.max(z - 0.2, 0.5))} className="p-2 hover:bg-white/10 rounded text-white"><ZoomOut className="w-4 h-4" /></button>
                 <button onClick={() => { setZoom(1); setPan({x:0,y:0}) }} className="p-2 hover:bg-white/10 rounded text-white"><Grip className="w-4 h-4" /></button>
             </div>
        </div>

        {/* Test Button */}
        <div className="absolute top-6 right-80 z-40">
            <button 
                onClick={handleRunTest}
                className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 rounded-xl text-white transition-all shadow-lg hover:shadow-indigo-500/30"
            >
                {isTestRunning ? <Loader2 className="w-4 h-4 animate-spin" /> : <Play className="w-4 h-4 fill-white" />}
                <span className="text-xs font-bold">Run Simulation</span>
            </button>
        </div>
      </div>

      {/* RIGHT SIDEBAR: INSPECTOR */}
      <AnimatePresence>
         {selectedNode && (
            <motion.div 
                initial={{ x: 320, opacity: 0 }} 
                animate={{ x: 0, opacity: 1 }} 
                exit={{ x: 320, opacity: 0 }} 
                transition={{ type: "spring", stiffness: 300, damping: 30 }}
                className="w-80 bg-[#0F1019] border-l border-white/10 flex flex-col z-30 shadow-2xl relative"
            >
               {/* Inspector Header */}
               <div className="p-5 border-b border-white/10 flex justify-between items-center bg-white/5">
                  <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-xl flex items-center justify-center shadow-inner border border-white/5 bg-gradient-to-br from-slate-800 to-black">
                          <NodeIcon type={selectedNode.type} className="w-5 h-5 text-slate-300" />
                      </div>
                      <div>
                          <h2 className="font-bold text-white text-sm tracking-wide">{selectedNode.label.split('.')[1] || selectedNode.label}</h2>
                          <p className="text-[10px] text-slate-500 font-mono uppercase tracking-wider">{WORKFLOW_PHASES[selectedNode.type as keyof typeof WORKFLOW_PHASES]?.label}</p>
                      </div>
                  </div>
                  <button onClick={() => setSelectedNodeId(null)} className="hover:bg-white/10 p-1.5 rounded-lg text-slate-400 hover:text-white transition-colors">
                      <X className="w-4 h-4" />
                  </button>
               </div>

               {/* Inspector Body */}
               <div className="flex-1 p-5 space-y-8 overflow-y-auto scrollbar-thin scrollbar-thumb-white/10">

                  {/* Provider Selection (Restricted) */}
                  <div>
                      <SectionHeader label="Integration Provider" />
                      <ProviderSelector 
                          node={selectedNode} 
                          updateProvider={updateNodeProvider} 
                      />
                  </div>

                  {/* Configuration */}
                  <div>
                      <SectionHeader label="Node Configuration" />
                      <div className="space-y-4">
                          <ConfigInput label="Endpoint / Connection String" value="https://api.gateway.internal/v1/hook" />
                          <ConfigInput label="Authentication" value="OAuth 2.0 (Connected)" secure />

                          <div className="flex gap-2">
                              <div className="flex-1">
                                  <ConfigInput label="Timeout (ms)" value="5000" />
                              </div>
                              <div className="flex-1">
                                  <ConfigInput label="Retries" value="3" />
                              </div>
                          </div>
                      </div>
                  </div>

               </div>

               {/* Inspector Footer */}
               <div className="p-4 border-t border-white/10 bg-black/20 flex justify-between items-center">
                   <button 
                       onClick={handleDeleteNode}
                       className="text-xs text-red-400 hover:text-red-300 px-3 py-2 hover:bg-red-500/10 rounded-lg transition-colors flex items-center gap-1"
                   >
                       <X className="w-3 h-3" /> Remove Node
                   </button>
                   <button className="px-4 py-2.5 rounded-lg text-xs font-bold bg-indigo-600 text-white hover:bg-indigo-500 shadow-lg shadow-indigo-900/20 transition-colors">
                       Save Changes
                   </button>
               </div>
            </motion.div>
         )}
      </AnimatePresence>
    </div>
  );
};

// --- SUB-COMPONENTS ---

const DraggableItem: React.FC<{ name: string; config: ProviderConfig }> = ({ name, config }) => {
    const handleDragStart = (e: React.DragEvent) => {
        e.dataTransfer.setData('provider', name);
        e.dataTransfer.effectAllowed = 'copy';
    };

    const isAedil = name.includes('AEDIL') || name.includes('Curio');

    return (
        <div 
            draggable 
            onDragStart={handleDragStart}
            className={`
                px-3 py-2 rounded-lg border flex items-center gap-3 cursor-grab active:cursor-grabbing hover:translate-x-1 transition-all
                ${isAedil ? 'bg-amber-500/5 border-amber-500/20 hover:border-amber-500/40' : 'bg-black/20 border-white/5 hover:border-white/10 hover:bg-white/5'}
            `}
        >
            <div className={`p-1.5 rounded-md bg-white/5 ${isAedil ? 'text-amber-400' : 'text-slate-400'}`}>
                <config.icon className="w-3.5 h-3.5" />
            </div>
            <div>
                <div className={`text-xs font-bold ${isAedil ? 'text-amber-100' : 'text-slate-300'}`}>{name}</div>
                <div className="text-[9px] text-slate-600">{config.category}</div>
            </div>
            {isAedil && <Sparkles className="w-3 h-3 text-amber-500 ml-auto animate-pulse" />}
        </div>
    );
};

const PaletteCategory = ({ title, type }: { title: string, type: NodeType }) => {
    const items = Object.entries(PROVIDER_LIBRARY).filter(([key, config]) => config.type === type);

    return (
        <div className="mb-4">
            <div className="px-2 mb-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                <span className={`w-1.5 h-1.5 rounded-full ${WORKFLOW_PHASES[type as keyof typeof WORKFLOW_PHASES]?.bg.replace('/10','/50')}`}></span>
                {title}
            </div>
            <div className="space-y-1">
                {items.map(([key, config]) => (
                    <DraggableItem key={key} name={key} config={config} />
                ))}
            </div>
        </div>
    );
};

const GlassNode = ({ node, selected, isTesting }: any) => {
    const providerConfig = PROVIDER_LIBRARY[node.provider] || DEFAULT_PROVIDER;
    const Icon = providerConfig.icon;

    const phase = WORKFLOW_PHASES[node.type as keyof typeof WORKFLOW_PHASES] || WORKFLOW_PHASES.system;
    const isAedil = node.provider.includes('AEDIL') || node.provider.includes('Curio');

    return (
        <motion.div 
            layoutId={node.id} 
            initial={{ scale: 0, opacity: 0 }} 
            animate={{ scale: selected ? 1.05 : 1, opacity: 1 }} 
            exit={{ scale: 0, opacity: 0 }} 
            data-node-id={node.id} 
            className={`
                absolute w-[240px] h-[120px] rounded-2xl pointer-events-auto transition-all duration-200 group cursor-grab active:cursor-grabbing backdrop-blur-md overflow-hidden flex flex-col
                ${selected 
                    ? 'bg-[#1E1E2E]/95 ring-2 shadow-[0_0_50px_-10px_rgba(99,102,241,0.4)] z-20' 
                    : 'bg-[#0F1019]/90 border border-white/10 hover:border-white/30 shadow-xl z-10'
                }
                ${isAedil ? 'shadow-[0_0_30px_-5px_rgba(245,158,11,0.15)]' : ''}
            `} 
            style={{ 
                left: node.position.x, 
                top: node.position.y,
                borderColor: selected ? providerConfig.color : (isAedil ? 'rgba(245,158,11,0.3)' : 'rgba(255,255,255,0.1)')
            }}
        >
            <div className={`h-8 px-4 flex items-center gap-2 border-b border-white/5 ${phase.bg}`}>
                <div className={`w-2 h-2 rounded-full ${phase.color.replace('text-','bg-')}`}></div>
                <span className={`text-[10px] font-bold uppercase tracking-wider ${phase.color}`}>{phase.label.split('.')[1]}</span>
                {isAedil && <span className="ml-auto text-[9px] font-bold text-amber-400 border border-amber-500/30 px-1.5 rounded bg-amber-500/10">AI</span>}
            </div>

            <div className="flex-1 p-4 flex flex-col relative z-10">
                <div className="flex items-start gap-3.5 mb-auto">
                    <div 
                        className="w-10 h-10 rounded-xl flex items-center justify-center shadow-lg border border-white/5 shrink-0 bg-white/5"
                    >
                        <Icon style={{ color: providerConfig.color }} className="w-5 h-5" strokeWidth={2} />
                    </div>

                    <div>
                        <div className="text-[13px] font-bold text-white leading-tight mb-0.5">{node.provider}</div>
                        <div className="text-[10px] text-slate-400 font-medium">{providerConfig.category}</div>
                    </div>
                </div>

                <div className="flex items-center justify-between mt-auto pt-2">
                    <div className="flex items-center gap-1.5 text-[9px] text-slate-500 font-mono">
                        {isTesting ? (
                            <>
                                <Loader2 className="w-3 h-3 animate-spin text-emerald-500" />
                                <span className="text-emerald-500">Processing...</span>
                            </>
                        ) : (
                            <span className="flex items-center gap-1"><span className="w-1.5 h-1.5 rounded-full bg-slate-600"></span> Idle</span>
                        )}
                    </div>
                </div>
            </div>

            {isTesting && (
                <div className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-emerald-500 rounded-full border-2 border-[#0F1019] z-30 animate-ping" />
            )}

            {node.type !== 'trigger' && (
                <div className="absolute -left-1.5 top-1/2 -translate-y-1/2 w-3 h-3 rounded-full bg-[#1E293B] border border-slate-600 shadow-sm group-hover:scale-125 transition-transform" />
            )}
            {node.type !== 'action' && (
                <div className="absolute -right-1.5 top-1/2 -translate-y-1/2 w-3 h-3 rounded-full bg-[#1E293B] border border-slate-600 shadow-sm group-hover:scale-125 transition-transform" />
            )}
        </motion.div>
    );
};

const SectionHeader = ({ label }: { label: string }) => (
    <div className="flex items-center gap-3 mb-4">
        <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{label}</div>
        <div className="h-px flex-1 bg-white/10"></div>
    </div>
);

const ConfigInput = ({ label, value, secure }: { label: string, value: string, secure?: boolean }) => (
    <div>
        <label className="text-[10px] font-bold text-slate-400 mb-1.5 block uppercase tracking-wide">{label}</label>
        <div className="relative">
            <input 
                type={secure ? "password" : "text"} 
                defaultValue={value} 
                className="w-full bg-black/30 border border-white/10 rounded-lg px-3 py-2.5 text-xs text-slate-200 font-mono focus:border-indigo-500/50 focus:ring-1 focus:ring-indigo-500/20 outline-none transition-all shadow-inner" 
            />
            {secure && <ShieldCheck className="absolute right-3 top-2.5 w-3.5 h-3.5 text-emerald-500" />}
        </div>
    </div>
);

const ProviderSelector = ({ node, updateProvider }: any) => { 
    const allowedProviders = Object.entries(PROVIDER_LIBRARY).filter(([name, config]) => {
        return config.allowedTypes.includes(node.type);
    });

    if (allowedProviders.length === 0) {
        return <div className="text-xs text-slate-500 italic p-4 text-center">No providers available for this phase.</div>;
    }

    return (
        <div className="grid grid-cols-1 gap-2">
            {allowedProviders.map(([name, config]) => (
                <div 
                    key={name} 
                    onClick={() => updateProvider(node.id, name)} 
                    className={`
                        p-3 rounded-xl border cursor-pointer flex items-center justify-between transition-all group
                        ${node.provider === name 
                            ? 'bg-indigo-500/10 border-indigo-500/50 shadow-sm' 
                            : 'bg-black/20 border-white/5 hover:bg-white/5 hover:border-white/10'
                        }
                    `}
                >
                    <div className="flex items-center gap-3">
                        <div 
                            className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0"
                            style={{ backgroundColor: `${config.color}20` }}
                        >
                            <config.icon style={{ color: config.color }} className="w-4 h-4" />
                        </div>
                        <div>
                            <div className={`text-xs font-bold ${node.provider === name ? 'text-white' : 'text-slate-300'}`}>{name}</div>
                            <div className="text-[10px] text-slate-500">{config.description}</div>
                        </div>
                    </div>
                    {node.provider === name && <CheckCircle className="w-4 h-4 text-indigo-400" />}
                </div>
            ))}
        </div>
    ); 
}

const NodeIcon = ({ type, className }: { type: NodeType, className?: string }) => { 
    switch (type) { 
        case 'trigger': return <Zap className={className} />; 
        case 'system': return <Database className={className} />; 
        case 'agent': return <Brain className={className} />; 
        case 'logic': return <Map className={className} />; 
        case 'action': return <Smartphone className={className} />; 
        default: return <Settings className={className} />; 
    } 
};

import { create } from 'zustand';
import { 
  AppId, WindowState, AgentLog, SapFormState, Email, 
  Diagnosis, MobileState, PortaState, AgentState, 
  WorkflowNode, WorkflowEdge, Ticket, ChatMessage,
  KnowledgeNode, KnowledgeEdge, LearningEvent, OSState
} from './types';
import { MOCK_TICKETS } from './constants';

const getApiKey = () => {
  try { return process.env.API_KEY || ""; } catch (e) { return ""; }
};

interface OSStore extends OSState {
  openApp: (id: AppId) => void;
  closeApp: (id: AppId) => void;
  minimizeApp: (id: AppId) => void;
  focusApp: (id: AppId) => void;
  toggleMaximizeApp: (id: AppId) => void;
  updateWindowPosition: (id: AppId, pos: { x: number; y: number }) => void;
  updateWindowSize: (id: AppId, size: { width: number; height: number }) => void;
  selectEmail: (id: string | null) => void;
  updateEmailBody: (id: string, body: string) => void;
  setOpenAIApiKey: (key: string) => void;
  addAgentLog: (type: AgentLog['type'], message: string) => void;
  performScan: () => void;
  performAutoFill: () => void;
  performDiagnosis: () => void;
  performDispatch: () => void;
  selectDispatchSlot: (techId: string, techName: string, time: string) => void;
  finalizeDispatch: () => void;
  submitDiagnosisFeedback: (ticketId: string, status: 'approved' | 'rejected', reason?: string) => void;
  viewTicketAnalysis: (id: string) => void;
  closeTicketAnalysis: () => void;
  manualOverride: () => void;
  switchToApp: (id: AppId) => void;
  orderParts: () => void;
  toggleSmartLens: (open: boolean) => void;
  addPortaMessage: (sender: ChatMessage['sender'], text: string) => void;
  setPortaStatus: (status: PortaState['status']) => void;
  finalizePortaSession: (extractedFields?: any[]) => Promise<void>;
  runGoldenPathSimulation: () => void; // NEW ACTION
  updateSapField: (field: keyof SapFormState, value: any) => void;
  updateNodeProvider: (nodeId: string, provider: string) => void;
  addWorkflowNode: (type: any, label: string, provider: string, parentId?: string, pos?: any) => void;
  updateWorkflowNodePosition: (id: string, x: number, y: number) => void;
  deleteWorkflowNode: (id: string) => void;
}

const DEFAULT_WINDOWS: Record<AppId, WindowState> = {
  outlook: { id: 'outlook', title: 'Outlook Web', isOpen: true, isMinimized: false, isMaximized: false, zIndex: 10 },
  sap: { id: 'sap', title: 'SAP S/4HANA', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 11 },
  fsm: { id: 'fsm', title: 'IFS FSM', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 12 },
  mobile: { id: 'mobile', title: 'Technician Mobile', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 13, size: { width: 340, height: 680 } },
  console: { id: 'console', title: 'AEDIL Console', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 14 },
  settings: { id: 'settings', title: 'Settings', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 15 },
  porta: { id: 'porta', title: 'AEDIL Porta', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 16, size: { width: 340, height: 680 } },
};

export const useOS = create<OSStore>()((set, get) => ({
  windows: DEFAULT_WINDOWS,
  activeAppId: 'outlook',
  theme: 'dark',
  tickets: [],
  emails: [],
  selectedEmailId: null,
  sapForm: {
    orderType: 'SV01',
    equipment: '',
    soldToParty: '',
    priority: '',
    shortText: '',
    errorDesc: '',
    isDirty: false
  },
  assignedTech: null,
  dispatchStatus: 'idle',
  selectedSlot: null,
  diagnosis: null,
  mobile: { isOpen: false, diagnosisStatus: 'pending', partsOrdered: false, chatHistory: [], debriefStatus: 'pending', feedback: null },
  porta: { messages: [{ id: '1', sender: 'ai', text: 'Jungheinrich Service Support. Nennen Sie bitte Ihren Namen und Ihre Firma.', timestamp: Date.now() }], status: 'idle', transcript: '' },
  agent: { status: 'idle', activeTask: null, logs: [] },
  workflowNodes: [],
  workflowEdges: [],
  isGeneratingWorkflow: false,
  knowledgeNodes: [],
  knowledgeEdges: [],
  learningEvents: [],
  cortexMessages: [],
  isCortexThinking: false,
  inspectingTicketId: null,

  openApp: (id) => set(state => ({
    windows: { ...state.windows, [id]: { ...state.windows[id], isOpen: true, isMinimized: false } },
    activeAppId: id
  })),
  closeApp: (id) => set(state => ({ windows: { ...state.windows, [id]: { ...state.windows[id], isOpen: false } } })),
  minimizeApp: (id) => set(state => ({ windows: { ...state.windows, [id]: { ...state.windows[id], isMinimized: true } } })),
  focusApp: (id) => set(state => ({
    activeAppId: id,
    windows: { 
      ...state.windows, 
      [id]: { 
        ...state.windows[id], 
        zIndex: Math.max(0, ...Object.values(state.windows).map(w => (w as WindowState).zIndex)) + 1 
      } 
    }
  })),
  toggleMaximizeApp: (id) => set(state => ({ windows: { ...state.windows, [id]: { ...state.windows[id], isMaximized: !state.windows[id].isMaximized } } })),
  updateWindowPosition: (id, pos) => set(state => ({ windows: { ...state.windows, [id]: { ...state.windows[id], position: pos } } })),
  updateWindowSize: (id, size) => set(state => ({ windows: { ...state.windows, [id]: { ...state.windows[id], size } } })),
  selectEmail: (id) => set({ selectedEmailId: id }),
  updateEmailBody: (id, body) => set(state => ({ emails: state.emails.map(e => e.id === id ? { ...e, body } : e) })),
  setOpenAIApiKey: (key) => set({ openaiApiKey: key }),
  addAgentLog: (type, message) => set(state => ({
    agent: { ...state.agent, logs: [...state.agent.logs, { id: Math.random().toString(), timestamp: Date.now(), type, message }] }
  })),
  performScan: () => {
    const { addAgentLog, selectedEmailId, emails } = get();
    const email = emails.find(e => e.id === selectedEmailId);
    if (!email) return;
    addAgentLog('thinking', 'Scanning email for service entities...');
    setTimeout(() => {
      const isGold = email.body.includes('Müller') || email.body.includes('Logistik GmbH') || email.body.includes('91165099');
      set(state => ({
        emails: state.emails.map(e => e.id === selectedEmailId ? {
          ...e,
          data: isGold ? {
            ticketId: '1165099',
            customer: 'Müller Logistik GmbH',
            customerAddress: "21033 Hamburg, Billwerder Ring 42",
            debitorId: '51109912',
            equipment: 'ETM 214',
            error: '3xxx Errors / Shutdown',
            priority: '1-Very High',
            desc: 'Fahrzeug geht sporadisch komplett aus.'
          } : {
            ticketId: '11447115',
            customer: 'DMK Milchkontor',
            debitorId: '11316498',
            equipment: 'EJC 220',
            error: 'E0015',
            priority: '2-High',
            desc: 'Hydraulic system fault'
          }
        } : e)
      }));
      addAgentLog('success', isGold ? 'Entities extracted: Müller Logistik GmbH, ETM 214, SN: 91165099.' : 'Entities extracted: DMK Milchkontor, EJC 220, E0015.');
    }, 1500);
  },
  performAutoFill: () => {
    const { addAgentLog, emails, selectedEmailId } = get();
    const email = emails.find(e => e.id === selectedEmailId);
    if (!email?.data) return;
    addAgentLog('action', 'Injecting data into SAP mask...');
    set(state => ({
      sapForm: {
        ...state.sapForm,
        equipment: email.data!.equipment,
        soldToParty: email.data!.debitorId,
        customerName: email.data!.customer,
        customerAddress: email.data!.customerAddress || "21033 Hamburg, Billwerder Ring 42",
        priority: email.data!.priority,
        shortText: email.data!.desc,
        errorDesc: email.body,
        isDirty: true
      }
    }));
  },
  performDiagnosis: async () => {
    const { addAgentLog, tickets } = get();
    set(state => ({ agent: { ...state.agent, status: 'diagnosing' } }));
    addAgentLog('thinking', 'Running multi-agent diagnosis...');
    const { CurioService } = await import('./services/curio');
    const targetTicket = tickets[0] || MOCK_TICKETS[0];
    const diagnosisResult = await CurioService.generateRealDiagnosis(targetTicket.id, targetTicket);
    set(state => ({ diagnosis: diagnosisResult as Diagnosis, agent: { ...state.agent, status: 'idle' } }));
    addAgentLog('success', `Diagnosis complete: ${diagnosisResult.primaryFault?.fault}`);
  },
  performDispatch: () => { set({ dispatchStatus: 'planning' }); get().addAgentLog('action', 'Opening IFS FSM for scheduling...'); get().openApp('fsm'); },
  selectDispatchSlot: (techId, techName, time) => set({ selectedSlot: { techId, techName, time }, dispatchStatus: 'review' }),
  finalizeDispatch: () => {
    const { selectedSlot, addAgentLog } = get();
    if (!selectedSlot) return;
    set({ dispatchStatus: 'confirmed', assignedTech: selectedSlot.techName });
    addAgentLog('success', `Job dispatched to ${selectedSlot.techName} for ${selectedSlot.time}`);
  },
  submitDiagnosisFeedback: (ticketId, status) => set(state => ({ diagnosis: state.diagnosis ? { ...state.diagnosis, feedback: { status, timestamp: Date.now() } } : null })),
  viewTicketAnalysis: (id) => set({ inspectingTicketId: id, activeAppId: 'console' }),
  closeTicketAnalysis: () => set({ inspectingTicketId: null }),
  manualOverride: () => set({ diagnosis: null }),
  switchToApp: (id) => get().openApp(id),
  orderParts: () => set(state => ({ mobile: { ...state.mobile, partsOrdered: true } })),
  toggleSmartLens: (open) => set(state => ({ mobile: { ...state.mobile, isOpen: open } })),
  addPortaMessage: (sender, text) => set(state => ({ porta: { ...state.porta, messages: [...state.porta.messages, { id: Math.random().toString(), sender, text, timestamp: Date.now() }] } })),
  setPortaStatus: (status) => set(state => ({ porta: { ...state.porta, status } })),

  // SIMULATION BACKUP FOR DEMOS
  runGoldenPathSimulation: () => {
     const { addPortaMessage, setPortaStatus, finalizePortaSession } = get();

     // 1. Reset Session
     set(state => ({ porta: { messages: [], status: 'idle', transcript: '' } }));

     // 2. Play out the "Perfect" Scenario
     setTimeout(() => {
         addPortaMessage('ai', 'Jungheinrich Service Support. Nennen Sie bitte Ihren Namen und Ihre Firma.');
     }, 100);

     setTimeout(() => {
         setPortaStatus('listening');
     }, 1000);

     // Simulate typing/speaking
