                                      className={`flex items-center justify-between text-[11px] bg-black/20 p-2 rounded-lg border transition-all cursor-pointer ${isSelected ? 'border-indigo-500/50 bg-indigo-500/10' : 'border-white/5 hover:bg-white/5'}`}
                                  >
                                      <div className="flex items-center gap-2">
                                        <Info className="w-3 h-3 text-slate-500" />
                                        <span className="text-slate-300 font-medium truncate max-w-[150px]">{part.name}</span>
                                      </div>
                                      <div className="flex items-center gap-2">
                                          {part.confidence && (
                                              <span className="text-[9px] text-slate-400 font-mono bg-white/5 px-1 rounded">{part.confidence.toFixed(2)}%</span>
                                          )}
                                          {part.inStock ? (
                                              <span className="flex items-center gap-1 text-[9px] text-emerald-400 font-bold bg-emerald-500/10 px-1.5 py-0.5 rounded border border-emerald-500/20"><StockIcon className="w-2.5 h-2.5" /></span>
                                          ) : (
                                              <span className="flex items-center gap-1 text-[9px] text-amber-400 font-bold bg-amber-500/10 px-1.5 py-0.5 rounded border border-amber-500/20">Order</span>
                                          )}
                                      </div>
                                  </div>
                                  {isSelected && part.reasoning && (
                                      <motion.div 
                                         initial={{ opacity: 0, height: 0 }} 
                                         animate={{ opacity: 1, height: 'auto' }} 
                                         className="text-[10px] text-indigo-200 bg-indigo-900/20 p-2 rounded-md border-l-2 border-indigo-500 ml-2"
                                      >
                                          {part.reasoning}
                                      </motion.div>
                                  )}
                               </div>
                           );
                        })}
                    </div>
                ) : (
                    <div className="text-[10px] text-slate-500 italic px-2">No specific parts required.</div>
                )}
            </div>

         </motion.div>
      )}
    </div>
  );
};

const getLogIcon = (type: string) => {
   switch (type) {
      case 'success': return <div className="w-2 h-2 rounded-full bg-emerald-400 shadow-[0_0_8px_rgba(52,211,153,0.6)]"></div>;
      case 'error': return <AlertCircle className="w-3 h-3 text-red-400" />;
      case 'action': return <Zap className="w-3 h-3 text-amber-400 fill-amber-400" />;
      case 'thinking': return <Loader2 className="w-3 h-3 text-indigo-400 animate-spin" />;
      default: return <div className="w-1.5 h-1.5 rounded-full bg-slate-600"></div>;
   }
};

const ActivityIcon = ({ className }: any) => <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M22 12h-4l-3 9L9 3l-3 9H2" /></svg>;

const ContextualActions = () => {
   const { activeAppId, agent, selectedEmailId, sapForm, performAutoFill, performDispatch, switchToApp, emails, performScan, performDiagnosis, diagnosis, submitDiagnosisFeedback, viewTicketAnalysis, manualOverride, dispatchStatus, finalizeDispatch, selectedSlot } = useOS();
   const activeEmail = emails.find(e => e.id === selectedEmailId);
   const hasData = activeEmail?.data;

   if (activeAppId === 'outlook') {
      if (!hasData && activeEmail) {
         return <div className="p-5 pt-2 z-10 bg-gradient-to-t from-[#0A0A0A] via-[#0A0A0A] to-transparent pb-6"><ActionButton onClick={performScan} label="Scan & Extract Entities" subLabel="AI Analysis" icon={Sparkles} color="indigo" /></div>;
      }
      if (hasData) {
         return <div className="p-5 pt-2 z-10 bg-gradient-to-t from-[#0A0A0A] via-[#0A0A0A] to-transparent pb-6"><ActionButton onClick={() => switchToApp('sap')} label="Open SAP S/4HANA" subLabel="Data Ready for Transfer" icon={LayoutGrid} color="blue" /></div>;
      }
      return <div className="p-5 pt-2 z-10 bg-gradient-to-t from-[#0A0A0A] via-[#0A0A0A] to-transparent pb-6"><div className="text-[11px] text-center text-slate-500 py-2 border border-dashed border-white/10 rounded-xl">Select an email to activate Neural Core</div></div>;
   }

   if (activeAppId === 'sap') {
      if (!sapForm.equipment && hasData) return <div className="p-5 pt-2 z-10 bg-gradient-to-t from-[#0A0A0A] via-[#0A0A0A] to-transparent pb-6"><ActionButton onClick={performAutoFill} label="Inject Data to Mask" subLabel="Auto-Fill Form" icon={Copy} color="amber" /></div>;
      if (sapForm.equipment && sapForm.isDirty) {
          if (!diagnosis) return <div className="p-5 pt-2 z-10 bg-gradient-to-t from-[#0A0A0A] via-[#0A0A0A] to-transparent pb-6"><ActionButton onClick={performDiagnosis} label="Run Diagnostics" subLabel="Multi-Agent Analysis" icon={Brain} color="purple" /></div>;
          else if (diagnosis.isComplete) {
             return (
               <div className="p-5 pt-2 z-10 bg-gradient-to-t from-[#0A0A0A] via-[#0A0A0A] to-transparent pb-6">
                   <div className="flex flex-col gap-2">
                      <ActionButton onClick={() => { submitDiagnosisFeedback(diagnosis.ticketId, 'approved'); performDispatch(); }} label="Approve & Dispatch" subLabel="Send to Technician" icon={Zap} color="emerald" />
                      <div className="flex gap-2">
                         <button onClick={() => viewTicketAnalysis(diagnosis.ticketId)} className="flex-1 bg-[#1A1A20] hover:bg-[#202028] border border-white/10 text-white py-3 rounded-2xl text-xs font-bold transition-all flex items-center justify-center gap-2 group"><Search className="w-3.5 h-3.5 text-indigo-400 group-hover:text-indigo-300" /> Inspect</button>
                         <button onClick={manualOverride} className="flex-1 bg-[#1A1A20] hover:bg-red-500/10 border border-white/10 hover:border-red-500/30 text-slate-400 hover:text-red-400 py-3 rounded-2xl text-xs font-bold transition-all flex items-center justify-center gap-2"><X className="w-3.5 h-3.5" /> Reject</button>
                      </div>
                   </div>
               </div>
             );
          }
      }
   }

   if (activeAppId === 'fsm') {
      if (dispatchStatus === 'review' && selectedSlot) return <div className="p-5 pt-2 z-10 bg-gradient-to-t from-[#0A0A0A] via-[#0A0A0A] to-transparent pb-6"><ActionButton onClick={finalizeDispatch} label="Confirm & Send" subLabel={`Dispatch to ${selectedSlot.techName}`} icon={UserCheck} color="emerald" /></div>;
      return <div className="p-5 pt-2 z-10 bg-gradient-to-t from-[#0A0A0A] via-[#0A0A0A] to-transparent pb-6"><ActionButton onClick={() => switchToApp('mobile')} label="View Technician Device" subLabel="Live Mirror" icon={ArrowRight} color="zinc" /></div>;
   }

   return null;
};

const ActionButton = ({ onClick, label, subLabel, icon: Icon, color }: any) => {
   const colors: any = { indigo: "bg-indigo-600 hover:bg-indigo-500 shadow-indigo-500/25", blue: "bg-blue-600 hover:bg-blue-500 shadow-blue-500/25", amber: "bg-amber-600 hover:bg-amber-500 shadow-amber-500/25", purple: "bg-purple-600 hover:bg-purple-500 shadow-purple-500/25", emerald: "bg-emerald-600 hover:bg-emerald-500 shadow-emerald-500/25", zinc: "bg-zinc-700 hover:bg-zinc-600 shadow-zinc-500/25" };
   return (
      <motion.button whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }} onClick={onClick} className={`w-full py-3.5 px-5 rounded-2xl flex items-center gap-4 text-left shadow-lg transition-all group ${colors[color]}`}>
         <div className="w-10 h-10 rounded-xl bg-white/20 flex items-center justify-center shadow-inner group-hover:scale-110 transition-transform duration-300"><Icon className="w-5 h-5 text-white" /></div>
         <div><div className="text-xs font-bold text-white leading-tight">{label}</div><div className="text-[10px] text-white/70 font-medium">{subLabel}</div></div>
         <ArrowRight className="w-4 h-4 text-white/50 ml-auto group-hover:translate-x-1 transition-transform" />
      </motion.button>
   );
};

import { create } from 'zustand';
import { 
