                          </div>
                       </div>
                       {expandedPart === part.id && part.reasoning && (
                           <div className="bg-blue-50 p-3 rounded-lg text-[10px] text-blue-800 border border-blue-100">
                               <div className="font-bold mb-1 flex justify-between">
                                   <span>AI Reasoning</span>
                                   <span>{part.confidence ? `${part.confidence.toFixed(2)}%` : ''}</span>
                               </div>
                               {part.reasoning}
                           </div>
                       )}
                   </div>
               );
            })}
         </div>

         {!ordered ? (
            <button 
               onClick={orderParts}
               className={`w-full text-white py-3 rounded-xl text-xs font-bold shadow-lg active:scale-95 transition-all flex items-center justify-center gap-2 ${hasMissingParts ? 'bg-amber-600 shadow-amber-500/20' : 'bg-blue-600 shadow-blue-500/20'}`}
