                            </div>
                        </div>

                        <div className="h-px bg-white/5 w-full"></div>

                        <div>
                            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2"><FileText className="w-4 h-4" /> Beobachtungen (Key Evidence)</h3>
                            <div className="grid grid-cols-2 gap-4">{evidenceCards.map((card, i) => (<EvidenceCard key={i} title={card.title} source={card.source} value={card.value} subtext={card.subtext} status={card.status} statusColor={card.statusColor} icon={card.icon} />))}</div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const TimelineStep = ({ step, index, isLast }: any) => (
    <div className="relative pl-12 group">
        <div className={`absolute left-[29px] top-1 w-2.5 h-2.5 rounded-full border-2 border-[#08080C] z-10 transition-colors ${step.status === 'complete' ? 'bg-indigo-500 group-hover:bg-white' : 'bg-amber-500'}`}></div>
        <div className="flex flex-col gap-1 pb-4">
            <div className="flex items-center justify-between"><span className="text-xs font-bold text-slate-300 group-hover:text-white transition-colors">{step.action}</span><span className="text-[9px] font-mono text-slate-600">{step.duration}ms</span></div>
            <div className="flex items-center gap-2"><span className={`text-[9px] px-1.5 py-0.5 rounded border ${getSystemBadgeStyle(step.system)}`}>{step.system}</span>{step.result && <span className="text-[10px] text-slate-500 truncate max-w-[150px]">{step.result}</span>}</div>
        </div>
    </div>
);

const EvidenceCard = ({ title, source, value, subtext, status, statusColor = 'indigo', icon: Icon }: any) => {
    const statusStyles: any = { emerald: "bg-emerald-500/10 text-emerald-400 border-emerald-500/20", red: "bg-red-500/10 text-red-400 border-red-500/20", amber: "bg-amber-500/10 text-amber-400 border-amber-500/20", indigo: "bg-indigo-500/10 text-indigo-400 border-indigo-500/20" };
    return (
        <div className="bg-[#0A0A0F] border border-white/5 rounded-xl p-5 hover:border-white/10 transition-colors group">
            <div className="flex justify-between items-start mb-3"><div className="p-2 rounded-lg bg-white/5 group-hover:bg-white/10 transition-colors text-slate-400 group-hover:text-white"><Icon className="w-4 h-4" /></div><span className={`text-[10px] font-bold px-2 py-1 rounded border ${statusStyles[statusColor]}`}>{status}</span></div>
            <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">{source}</div>
            <div className="text-lg font-bold text-white mb-0.5">{value}</div>
            {subtext && <div className="text-xs text-indigo-400 mb-1">{subtext}</div>}
            <div className="text-[10px] text-slate-600">{title}</div>
        </div>
    );
};

