import { Diagnosis, ReasoningStep, Ticket, Part } from '../types';
import { RECOMMENDED_PARTS } from '../constants';

export const CurioService = {
  async generateRealDiagnosis(ticketId: string, ticket: Ticket): Promise<Partial<Diagnosis>> {
    const reasoningChain: ReasoningStep[] = [];
    const pushStep = (system: ReasoningStep['system'], action: string, status: ReasoningStep['status'], input?: any, output?: any) => {
        reasoningChain.push({
            id: Math.random().toString(),
            system, action, status,
            result: status === 'complete' ? 'Success' : undefined,
            input, output,
            timestamp: Date.now(),
            duration: Math.floor(Math.random() * 500) + 100
        });
    };

    pushStep('Reasoning', 'Initializing Curio Agent (Technical Report Mode)...', 'working');

    // 🔴 THE GOLDEN PATH IDENTIFIER
    // We treat 'context-ticket' (triggered from SAP Overlay) as Gold Standard to ensure the demo animation plays.
    const isGoldStandardCase = 
      ticketId === 'context-ticket' ||
      ticket.equipment.model.includes('214') || 
      ticket.equipment.serialNumber.includes('91165099') ||
      ticket.customer.name.toLowerCase().includes('müller') ||
      ticket.customer.name.toLowerCase().includes('gmbh');

    if (isGoldStandardCase) {
        // Step 1: Initialize & History
        await new Promise(r => setTimeout(r, 1200));
        pushStep('History', 'Checking Service History for SN 91165099', 'complete', { serial: '91165099' }, { result: 'Extremely high history: 39 service entries detected.' });

        // Step 2: Manuals & Voltage
        await new Promise(r => setTimeout(r, 1000));
        pushStep('Manuals', 'Correlating 3xxx Errors with Manuals', 'complete', { codes: '3xxx' }, { result: 'Mechanical resistance in steering motor leads to peak current and system shutdown.' });

        // Step 3: IoT & CAN-Bus
        await new Promise(r => setTimeout(r, 1000));
        pushStep('IoT', 'Monitoring CAN-Bus Activity Node 4', 'complete', { serial: '91165099' }, { result: 'High CAN-Bus activity on Node 4. Inconsistent Ist-Values.' });

        // Step 4: Final Reasoning
        await new Promise(r => setTimeout(r, 1000));
        pushStep('Reasoning', 'Determining Root Cause (Discriminator Logic)', 'complete', {}, { result: 'Verified: No Sensor-Error 3154. Voltage drops confirmed. Root Cause: Drehkranzlager.' });

        // Step 5: Wrap up (total ~4.2s to match visual animation)
        await new Promise(r => setTimeout(r, 500));

        // Map Parts with Exact PDF Data
        const enrichedParts: Part[] = RECOMMENDED_PARTS.filter(p => ['50452065', '51509314', '51470075'].includes(p.id)).map(p => {
             if (p.id === '50452065') {
                 // Rang 1
                 return { ...p, rank: 1, confidence: 48.33, reasoning: "Hauptursache: Mechanische Überlastung führt zu Stromspitzen und Abschaltung. Handbuch bestätigt Prüfung mechanischer Probleme bei diesem Fehlerbild." };
             }
             if (p.id === '51509314') {
                 // Rang 2
                 return { ...p, rank: 2, confidence: 13.13, reasoning: "Wäre primär bei rein elektronischen Fehlern (z.B. Positionsverlust) relevant. Hier liegen mechanische Symptome vor." };
             }
             if (p.id === '51470075') {
                 // Rang 3
                 return { ...p, rank: 3, confidence: 11.54, reasoning: "Unwahrscheinlich. Ein Defekt hier führt meist zu Schleichgang, nicht zur Komplettabschaltung." };
             }
             return p;
        });

        return {
            ticketId,
            timestamp: Date.now(),
            primaryFault: {
                fault: 'Rep. Satz; Drehkranzlager (Rang 1)',
                confidence: 48.33,
                // SHORT REASONING for Overlay (High Level)
                shortReasoning: 'Mechanischer Widerstand verursacht Spannungsabfall und Abschaltung. Keine Sensorfehler (3154).',
                // LONG REASONING for Console (Deep Dive)
                reasoning: 'Das Drehkranzlager der Lenkung ist stark verschlissen oder schwergängig. Der Lenkmotor muss permanent gegen diesen hohen Widerstand ankämpfen, was das elektrische System bis zum Zusammenbruch belastet (Spannungseinbrüche -> Selbstschutz). Die vielen unspezifischen Lenkfehler (3xxx) und sogar Hardware-Kurzschlussfehler (0504) sind die Folge der mechanischen Überlastung, nicht die Ursache.'
            },
            secondaryFaults: [
                { 
                    fault: 'Sensorlager; kpl. montiert (Rang 2)', 
                    confidence: 13.13, 
                    reasoning: 'Das Sensorlager liefert falsche Werte. Dies würde jedoch eher zu Positionsfehlern führen als zur Abschaltung durch Spannungseinbruch.' 
                },
                { 
                    fault: 'Initiator (Sonder NPN) (Rang 3)', 
                    confidence: 11.54, 
                    reasoning: 'Verbindung zum Problem schwach. Führt normalerweise nur zu reduzierter Fahrgeschwindigkeit (Schleichgang), da Hubhöhe unbekannt.' 
                }
            ],
            requiredParts: enrichedParts.sort((a,b) => (a.rank || 99) - (b.rank || 99)),
            reasoningChain: reasoningChain,
            isComplete: true
        };
    }

    // Generic fallback
    await new Promise(r => setTimeout(r, 1500));
    return {
      ticketId,
      timestamp: Date.now(),
      primaryFault: {
        fault: 'Hydraulic Pump Motor Failure',
        confidence: 92.00,
        reasoning: 'Symptoms match Cluster 3 (Hydraulics). Lack of external oil leak suggests internal component failure.',
        shortReasoning: 'Cluster 3 match. No external leak.'
      },
      secondaryFaults: [],
      requiredParts: RECOMMENDED_PARTS.slice(3, 5).map((p, i) => ({ ...p, rank: i+1, confidence: 90 - (i*10), reasoning: 'Standard replacement for hydraulic fault.' })),
      reasoningChain: [
          { id: '1', system: 'Manuals', action: 'Analyze Symptom', status: 'complete', result: 'Hydraulic Fault', timestamp: Date.now() },
          { id: '2', system: 'IoT', action: 'Read Sensor Data', status: 'complete', result: 'Pressure Low', timestamp: Date.now() }
      ],
      isComplete: true
    };
  }
};

