          hintText = "Sync Mobile";
          accentColor = "from-zinc-600 to-zinc-400";
          Icon = ArrowRight;
      } else if (dispatchStatus === 'planning') {
          hintText = "Select Slot";
          accentColor = "from-amber-500 to-orange-500";
          Icon = MousePointer2;
      } else if (dispatchStatus === 'review' && selectedSlot) {
          hintText = "Confirm";
          accentColor = "from-emerald-500 to-teal-500";
          Icon = UserCheck;
      } else {
          hintText = "Schedule";
          accentColor = "from-purple-600 to-indigo-600";
      }
  }

  if (!isRelevant && !expanded) return null;

  return (
    <motion.div
       className="absolute top-[48px] right-[20px] z-[9999] pointer-events-auto flex flex-col items-end font-sans"
       initial={{ y: -10, opacity: 0 }}
       animate={{ y: 0, opacity: 1 }}
       transition={{ type: "spring", stiffness: 400, damping: 28 }}
    >
       <motion.div
          layout
          onClick={() => !expanded && setExpanded(true)}
          className={`relative overflow-hidden bg-[#0A0A0A]/95 backdrop-blur-2xl border border-white/15 shadow-[0_20px_60px_-10px_rgba(0,0,0,0.8),0_0_0_1px_rgba(255,255,255,0.1)] ${expanded ? 'cursor-default' : 'cursor-pointer group'}`}
          initial={false}
