          style={{ minWidth: expanded ? 360 : 44 }}
       >
          <motion.div className={`absolute inset-0 bg-gradient-to-br ${accentColor} opacity-5 transition-opacity duration-500 pointer-events-none`} />
          {expanded && (
             <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-indigo-500/20 via-purple-500/5 to-transparent pointer-events-none" />
