// --- INVESTIGATION SEQUENCE ANIMATION ---
const InvestigationSequence = () => {
    const [stepIndex, setStepIndex] = useState(0);

    const steps = [
        { label: "Initializing Curio Agent...", icon: Sparkles, color: "text-amber-400" },
        { label: "Checking Service History (SN 91165099)...", icon: History, color: "text-blue-400" },
        { label: "Correlating 3xxx Errors with Manuals...", icon: FileText, color: "text-purple-400" },
        { label: "Monitoring CAN-Bus Activity Node 4...", icon: Activity, color: "text-emerald-400" },
        { label: "Determining Root Cause...", icon: GitMerge, color: "text-white" }
    ];

    useEffect(() => {
        if (stepIndex < steps.length - 1) {
            const timeout = setTimeout(() => {
                setStepIndex(prev => prev + 1);
            }, 850); // Timing matches roughly with CurioService total duration
            return () => clearTimeout(timeout);
        }
    }, [stepIndex]);

    const currentStep = steps[stepIndex];
    const Icon = currentStep.icon;

    return (
        <div className="p-8 flex flex-col items-center justify-center min-h-[300px] text-center space-y-6 bg-black/40">
            <div className="relative">
                <div className="absolute inset-0 bg-indigo-500/20 blur-2xl rounded-full animate-pulse"></div>
                <motion.div 
                    key={stepIndex}
                    initial={{ scale: 0.8, opacity: 0, rotate: -20 }}
                    animate={{ scale: 1, opacity: 1, rotate: 0 }}
                    exit={{ scale: 1.2, opacity: 0 }}
                    transition={{ type: "spring", stiffness: 300, damping: 20 }}
                    className="w-20 h-20 bg-gradient-to-br from-[#1A1A24] to-[#0F0F13] border border-white/10 rounded-2xl flex items-center justify-center relative z-10 shadow-2xl"
                >
                    <Icon className={`w-10 h-10 ${currentStep.color}`} strokeWidth={1.5} />
                </motion.div>
            </div>

            <div className="space-y-2 max-w-[280px]">
                <motion.div
                    key={currentStep.label}
                    initial={{ y: 10, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    className="text-lg font-bold text-white tracking-tight leading-snug"
                >
                    {currentStep.label}
                </motion.div>
                <div className="h-1 w-full bg-white/10 rounded-full overflow-hidden mt-3">
                    <motion.div 
                        initial={{ width: `${(stepIndex / steps.length) * 100}%` }}
                        animate={{ width: `${((stepIndex + 1) / steps.length) * 100}%` }}
                        transition={{ duration: 0.8, ease: "linear" }}
                        className="h-full bg-indigo-500"
                    />
                </div>
            </div>

            <div className="grid grid-cols-5 gap-2 w-full max-w-[240px] pt-4 border-t border-white/5">
                {steps.map((s, i) => (
                    <div 
                        key={i} 
                        className={`h-1 rounded-full transition-all duration-300 ${i <= stepIndex ? 'bg-indigo-500' : 'bg-white/10'}`}
                    />
                ))}
            </div>
        </div>
    );
};

