// --- CINEMATIC INVESTIGATION SEQUENCE ---
const InvestigationSequence = () => {
    const [stepIndex, setStepIndex] = useState(0);

    // Matched closely to the 4.7s timing in CurioService
    const steps = [
        { label: "INITIALIZING CURIO AGENT...", subtext: "Context: ETM 214 / SN 91165099", icon: ScanFace, color: "text-amber-400", ringColor: "border-amber-500" },
        { label: "ANALYZING SERVICE HISTORY", subtext: "Retrieving 39 past entries...", icon: History, color: "text-blue-400", ringColor: "border-blue-500" },
        { label: "CORRELATING MANUALS", subtext: "Mapping 3xxx error patterns...", icon: FileText, color: "text-purple-400", ringColor: "border-purple-500" },
        { label: "CHECKING IOT TELEMETRY", subtext: "Scanning CAN-Bus Node 4...", icon: Radar, color: "text-emerald-400", ringColor: "border-emerald-500" },
        { label: "DETERMINING ROOT CAUSE", subtext: "Finalizing confidence score...", icon: Brain, color: "text-white", ringColor: "border-white" }
    ];

    useEffect(() => {
        // Advance step every ~950ms (roughly syncing with service)
        if (stepIndex < steps.length - 1) {
            const timeout = setTimeout(() => {
                setStepIndex(prev => prev + 1);
            }, 950); 
            return () => clearTimeout(timeout);
        }
    }, [stepIndex]);

    const currentStep = steps[stepIndex];
    const Icon = currentStep.icon;

    return (
        <div className="flex flex-col items-center justify-center min-h-[320px] text-center relative overflow-hidden">
            {/* Background Effects */}
            <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-indigo-900/20 via-[#0A0A0A] to-[#0A0A0A]"></div>

            {/* Central Animated Icon */}
            <div className="relative z-10 mb-8 mt-4">
                {/* Pulse Rings */}
                <div className={`absolute inset-0 rounded-full border-[1px] opacity-20 scale-150 animate-ping ${currentStep.ringColor}`}></div>
                <div className={`absolute inset-0 rounded-full border-[1px] opacity-40 scale-110 animate-pulse ${currentStep.ringColor}`}></div>

                <motion.div 
                    key={stepIndex}
                    initial={{ scale: 0.5, opacity: 0, rotateY: 90 }}
                    animate={{ scale: 1, opacity: 1, rotateY: 0 }}
                    exit={{ scale: 1.5, opacity: 0 }}
                    transition={{ type: "spring", stiffness: 200, damping: 20 }}
                    className="w-24 h-24 bg-gradient-to-br from-[#1A1A24] to-[#0F0F13] border border-white/10 rounded-full flex items-center justify-center shadow-[0_0_30px_-5px_rgba(0,0,0,0.5)]"
                >
                    <Icon className={`w-10 h-10 ${currentStep.color} drop-shadow-[0_0_10px_rgba(255,255,255,0.2)]`} strokeWidth={1.5} />
                </motion.div>
            </div>

            {/* Text Content */}
            <div className="space-y-2 max-w-[300px] z-10 min-h-[80px]">
                <motion.div
                    key={`text-${stepIndex}`}
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    className="text-lg font-bold text-white tracking-widest font-mono"
                >
                    {currentStep.label}
                </motion.div>
                <motion.div
                    key={`sub-${stepIndex}`}
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    transition={{ delay: 0.2 }}
                    className="text-xs text-indigo-300 font-medium"
                >
                    {currentStep.subtext}
                </motion.div>
            </div>

            {/* Progress Bar */}
            <div className="w-64 h-1 bg-white/10 rounded-full mt-6 overflow-hidden z-10">
                <motion.div 
                    initial={{ width: `${(stepIndex / steps.length) * 100}%` }}
                    animate={{ width: `${((stepIndex + 1) / steps.length) * 100}%` }}
                    transition={{ duration: 0.95, ease: "linear" }}
                    className="h-full bg-gradient-to-r from-indigo-500 to-purple-500"
                />
            </div>

            {/* Step Indicators */}
            <div className="flex gap-2 mt-3 z-10">
                {steps.map((_, i) => (
                    <div 
                        key={i} 
                        className={`w-1.5 h-1.5 rounded-full transition-all duration-300 ${i <= stepIndex ? 'bg-indigo-500 scale-110' : 'bg-white/10'}`}
                    />
                ))}
            </div>
        </div>
    );
};

