                         <button onClick={manualOverride} className="flex-1 bg-[#1A1A20] hover:bg-red-500/10 border border-white/10 hover:border-red-500/30 text-slate-400 hover:text-red-400 py-3 rounded-2xl text-xs font-bold transition-all flex items-center justify-center gap-2"><X className="w-3.5 h-3.5" /> Reject</button>
